      border-color: var(--accent);
      transform: scale(1.05);
    }
    .pricing-card.featured::before {
      content: '{{FEATURED_BADGE}}';
      position: absolute;
      top: -12px;
      left: 50%;
      transform: translateX(-50%);
      background: var(--accent);
      color: var(--bg);
      padding: 4px 16px;
      border-radius: 20px;
