    }
    .tier-features li::before { content: '✅ '; }
    .tier-features li.no::before { content: '❌ '; opacity: 0.4; }

    .cta-btn {
      display: block;
      background: var(--accent);
      color: var(--bg);
      text-decoration: none;
      padding: 1rem 2rem;
      border-radius: 8px;
      font-weight: 600;
      font-size: 1.1rem;
      margin-top: 1rem;
      transition: opacity 0.2s;
    }
    .cta-btn:hover { opacity: 0.9; }

    .social-proof {
      text-align: center;
      padding: 3rem 1rem;
      font-size: 1.1rem;
      opacity: 0.8;
    }

    .faq {
      max-width: 800px;
