      padding: 2rem;
    }
    .faq details {
      background: var(--surface);
      border-radius: 8px;
      margin-bottom: 0.5rem;
      padding: 1rem;
    }
    .faq summary {
      cursor: pointer;
      font-weight: 600;
    }

    @media (max-width: 768px) {
      .pricing-card.featured { transform: scale(1); }
      .pricing-header h1 { font-size: 1.8rem; }
      .tier-price { font-size: 2.2rem; }
    }
  </style>
</head>
